import { useState, useEffect } from "react";
import "./Sidebar.css";

export default function Sidebar({ currentUser, friends, selectedFriend, onSelectFriend, onlineUsers, onLogout, onOpenProfile, messages, typingUser }) {
  const [search, setSearch] = useState("");
  const [unreadCounts, setUnreadCounts] = useState({});

  // Calculate unread counts
  useEffect(() => {
    if (!messages) return;
    const counts = {};
    messages.forEach(msg => {
      if (msg.receiver === currentUser.username && msg.status !== "seen") {
        counts[msg.sender] = (counts[msg.sender] || 0) + 1;
      }
    });
    setUnreadCounts(counts);
  }, [messages]);

  const filtered = friends.filter(f =>
    f.username.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="sidebar">
      {/* Header */}
      <div className="sidebar-header">
        <div className="sidebar-brand">
          <span className="brand-dot" />
          <h1 className="brand-name">Messages</h1>
        </div>
        <button className="my-avatar-btn" onClick={onOpenProfile} title="My Profile">
          <div className="my-avatar">
            {currentUser.profilePic
              ? <img src={currentUser.profilePic} alt="" />
              : currentUser.username[0].toUpperCase()
            }
          </div>
        </button>
      </div>

      {/* Search */}
      <div className="search-wrap">
        <span className="search-icon">🔍</span>
        <input
          className="search-input"
          placeholder="Search..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </div>

      <div className="section-label">PEOPLE</div>

      {/* Friend list */}
      <ul className="friend-list">
        {filtered.length === 0 && (
          <li className="no-results">No users found</li>
        )}
        {filtered.map(friend => {
          const isOnline   = onlineUsers.includes(friend.username);
          const isSelected = selectedFriend?.username === friend.username;
          const unread     = unreadCounts[friend.username] || 0;
          const isTyping   = typingUser === friend.username;

          return (
            <li
              key={friend._id}
              className={`friend-item ${isSelected ? "active" : ""}`}
              onClick={() => onSelectFriend(friend)}
            >
              <div className="friend-avatar-wrap">
                <div className="friend-avatar">
                  {friend.profilePic
                    ? <img src={friend.profilePic} alt="" />
                    : friend.username[0].toUpperCase()
                  }
                </div>
                <span className={`online-dot ${isOnline ? "on" : "off"}`} />
              </div>
              <div className="friend-info">
                <span className="friend-name">{friend.username}</span>
                <span className="friend-sub">
                  {isTyping
                    ? <span className="typing-text">typing...</span>
                    : isOnline ? "Active now" : "Offline"
                  }
                </span>
              </div>
              {unread > 0 && !isSelected && (
                <span className="unread-badge">{unread > 99 ? "99+" : unread}</span>
              )}
            </li>
          );
        })}
      </ul>

      {/* Logout */}
      <button className="logout-btn" onClick={onLogout}>
        <span>⏻</span> Logout
      </button>
    </div>
  );
}
